/**
 * Untangle — Instagram Carousel Exporter
 * Exports all carousel HTML files into carousel/MM-DD-YY/
 * alongside the reel.mp4 generated by make-reel.py.
 *
 * Run: node export-carousel.js
 */

const { chromium } = require('playwright');
const path = require('path');
const fs   = require('fs');

// ── Dated output folder (matches make-reel.py) ──────────────────────────────
const now    = new Date();
const mm     = String(now.getMonth() + 1).padStart(2, '0');
const dd     = String(now.getDate()).padStart(2, '0');
const yy     = String(now.getFullYear()).slice(-2);
const folder = `${mm}-${dd}-${yy}`;
const outDir = path.resolve(__dirname, folder);
if (!fs.existsSync(outDir)) fs.mkdirSync(outDir, { recursive: true });

// ── TODAY'S CAROUSEL ─────────────────────────────────────────────────────────
// Change this one line each time you make a new carousel.
// file:   the HTML file in this folder
// prefix: the filename prefix for exported PNGs  e.g. "burnout" → burnout-01.png
const TODAY = { file: 'carousel-burnout.html', prefix: 'burnout' };

// ── History (for reference only — not exported) ──────────────────────────────
// { file: 'carousel.html',         prefix: 'slide' }   // 05-05-26
// { file: 'carousel-2am.html',     prefix: '2am'   }   // 05-06-26
// { file: 'carousel-burnout.html', prefix: 'burnout' } // 05-07-26

const CAROUSELS = [TODAY];

(async () => {
  const browser = await chromium.launch();

  for (const { file, prefix } of CAROUSELS) {
    const htmlPath = path.resolve(__dirname, file);
    if (!fs.existsSync(htmlPath)) {
      console.log(`  Skipping ${file} — not found.`);
      continue;
    }

    const page = await browser.newPage();
    await page.setViewportSize({ width: 1080, height: 1080 });
    await page.goto(`file://${htmlPath}`, { waitUntil: 'networkidle' });
    await page.waitForTimeout(2000);

    const slideCount = await page.locator('.slide').count();
    if (slideCount === 0) {
      console.error(`  No .slide elements found in ${file}.`);
      await page.close();
      continue;
    }

    console.log(`\nExporting ${file} — ${slideCount} slides (prefix: ${prefix}-XX.png)`);

    for (let i = 0; i < slideCount; i++) {
      const slide   = page.locator('.slide').nth(i);
      const num     = String(i + 1).padStart(2, '0');
      const outFile = path.join(outDir, `${prefix}-${num}.png`);
      await slide.scrollIntoViewIfNeeded();
      await slide.screenshot({ path: outFile, type: 'png' });
      console.log(`  ${prefix}-${num}.png`);
    }

    await page.close();
  }

  await browser.close();

  // ── Write carousel caption ───────────────────────────────────────────────
  const caption = `You think you would know if you were burned out.

Most people don't. Here's what burnout actually looks like:

01. Scrolling for two hours and remembering nothing
02. Coming back from a trip just as hollow as when you left
03. Not falling apart at work. Just feeling nothing at home.
04. Waking up Monday morning just as empty as Friday night

If any of these hit — you are not lazy. You are running on empty.

The Running on Empty guide walks you through 7 days of honest, practical steps to find what is draining you and rebuild energy that actually lasts. 10 minutes a day. Link in bio.

—

#burnout #burnoutrecovery #mentalhealth #exhausted #runningonempty #energymanagement #selfcare #cbt #mentalhealthtips #burnoutawareness #selfhelp #mindset #innerpeace #digitaldownload #untangle`;

  const captionPath = path.join(outDir, 'carousel-caption.txt');
  fs.writeFileSync(captionPath, caption, 'utf8');
  console.log(`  carousel-caption.txt`);

  console.log(`\nDone. All files saved to: carousel/${folder}/`);
  console.log(`Run make-reel.py to add reel.mp4 + reel-caption.txt to the same folder.`);
})();
